import { describe, it, expect, vi, beforeEach } from 'vitest';

// We test the argument building logic by importing the module and checking the generated commands
// For unit tests, we mock spawnPM and detectPackageManager

vi.mock('../src/utils/spawn', () => ({
    spawnPM: vi.fn().mockResolvedValue({ exitCode: 0, stdout: '', stderr: '' }),
}));

vi.mock('../src/detect', () => ({
    detectPackageManager: vi.fn(),
}));

vi.mock('../src/utils/output', () => ({
    isJsonMode: vi.fn().mockReturnValue(false),
    printJSON: vi.fn(),
    printHuman: vi.fn(),
}));

import { install } from '../src/commands/install';
import { spawnPM } from '../src/utils/spawn';
import { detectPackageManager } from '../src/detect';

describe('install', () => {
    beforeEach(() => {
        vi.clearAllMocks();
    });

    it('should generate correct npm install command (no packages)', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'npm', version: '10.0.0', reason: 'lockfile', lockfile: 'package-lock.json' });
        await install([], {});
        expect(spawnPM).toHaveBeenCalledWith('npm', ['install'], expect.anything());
    });

    it('should generate correct pnpm add command (with packages)', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'pnpm', version: '8.0.0', reason: 'lockfile', lockfile: 'pnpm-lock.yaml' });
        await install(['lodash'], {});
        expect(spawnPM).toHaveBeenCalledWith('pnpm', ['add', 'lodash'], expect.anything());
    });

    it('should add -D flag for devDependencies', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'npm', version: '10.0.0', reason: 'default' });
        await install(['vitest'], { dev: true });
        expect(spawnPM).toHaveBeenCalledWith('npm', ['install', 'vitest', '-D'], expect.anything());
    });

    it('should add -g flag for global install', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'pnpm', version: '8.0.0', reason: 'default' });
        await install(['tsx'], { global: true });
        expect(spawnPM).toHaveBeenCalledWith('pnpm', ['add', 'tsx', '-g'], expect.anything());
    });

    it('should map yarn global correctly', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'yarn', version: '1.22.0', reason: 'lockfile', lockfile: 'yarn.lock' });
        await install(['tsx'], { global: true });
        expect(spawnPM).toHaveBeenCalledWith('yarn', ['global', 'add', 'tsx'], expect.anything());
    });

    it('should use -d for bun dev dependencies', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'bun', version: '1.0.0', reason: 'lockfile', lockfile: 'bun.lockb' });
        await install(['vitest'], { dev: true });
        expect(spawnPM).toHaveBeenCalledWith('bun', ['add', 'vitest', '-d'], expect.anything());
    });
});
